const nowIso = new Date().toISOString();

const parsePayload = (value) => {
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return { raw_body: value };
    }
  }
  if (value && typeof value === 'object') return value;
  return {};
};

const inbound = parsePayload($json.body ?? $json);
const event = String(inbound.event || '').trim().toLowerCase();

const scoreMap = {
  page_view: 1,
  artist_open: 3,
  share_click: 5,
  scroll_depth: Math.min(4, Math.max(1, Math.round((Number(inbound.depth) || 0) / 25))),
  poll_vote: 7,
  opt_in_submit: 10,
};

const delta = Number(scoreMap[event] || 0);
const email = String(inbound.email || '').trim().toLowerCase();
const anonId = String(inbound.anon_id || '').trim();
const profileKey = email || anonId || `anon:${Date.now()}`;

const store = getWorkflowStaticData('global');
store.profiles = store.profiles || {};
store.events = store.events || [];
store.leads = store.leads || {};

const profile = store.profiles[profileKey] || {
  key: profileKey,
  score: 0,
  counts: {},
  artists: {},
  firstSeenAt: nowIso,
};

profile.score += delta;
if (event) profile.counts[event] = (profile.counts[event] || 0) + 1;
if (inbound.artist_id) profile.artists[inbound.artist_id] = (profile.artists[inbound.artist_id] || 0) + 1;
profile.lastSeenAt = nowIso;
profile.utm_source = inbound.utm_source || profile.utm_source || '';
profile.campaign = inbound.campaign || profile.campaign || '';
profile.url = inbound.url || profile.url || '';

const topArtist = Object.entries(profile.artists)
  .sort((a, b) => b[1] - a[1])[0]?.[0] || null;
profile.topArtist = topArtist;
store.profiles[profileKey] = profile;

const eventRecord = {
  event,
  anon_id: anonId || null,
  email: email || null,
  artist_id: inbound.artist_id || null,
  depth: inbound.depth ?? null,
  platform: inbound.platform || null,
  url: inbound.url || null,
  utm_source: inbound.utm_source || '',
  campaign: inbound.campaign || '',
  received_at: nowIso,
  event_timestamp: inbound.timestamp || nowIso,
};

store.events.push(eventRecord);
if (store.events.length > 5000) {
  store.events = store.events.slice(-5000);
}

if (event === 'opt_in_submit' && email) {
  const lead = store.leads[email] || {
    email,
    firstSeenAt: nowIso,
    sources: {},
    campaigns: {},
    optInCount: 0,
  };

  lead.lastSeenAt = nowIso;
  lead.optInCount += 1;

  if (inbound.utm_source) {
    lead.sources[inbound.utm_source] = (lead.sources[inbound.utm_source] || 0) + 1;
  }

  if (inbound.campaign) {
    lead.campaigns[inbound.campaign] = (lead.campaigns[inbound.campaign] || 0) + 1;
  }

  lead.topArtist = topArtist || inbound.artist_id || lead.topArtist || null;
  store.leads[email] = lead;
}

let nextBestAction = 'continue_story';
if (!email && (profile.counts.artist_open || 0) >= 2) nextBestAction = 'show_poll';
if (!email && (profile.counts.poll_vote || 0) >= 1) nextBestAction = 'ask_opt_in';
if (email && topArtist) nextBestAction = 'send_artist_followup';
if ((profile.counts.share_click || 0) >= 1) nextBestAction = 'invite_ugc';

return [{
  json: {
    ok: true,
    accepted: Boolean(event),
    event,
    profile_key: profileKey,
    score_delta: delta,
    profile_score: profile.score,
    top_artist: topArtist,
    next_best_action: nextBestAction,
    store_counts: {
      profiles: Object.keys(store.profiles).length,
      events: store.events.length,
      leads: Object.keys(store.leads).length,
    },
  },
}];
